/* -------------------------------------------------
   4. Animaciأ³n de la grأ؛a
------------------------------------------------- */
@keyframes lift {
  0%   { transform: translateY(0); }
  30%  { transform: translateY(-30px); }   /* sube el gancho */
  60%  { transform: translateY(-30px); }   /* mantiene */
  100% { transform: translateY(0); }       /* vuelve */
}
.bg-crane::before {
  content: "";
  position: absolute;
  width: 120px;
  height: 150px;
  background: #555;
  border-radius: 10px;
  top: 20%;
  left: 50%;
  transform: translateX(-50%);
  animation: lift 4s ease-in-out infinite;
  /* Dibujamos la grأ؛a con pseudoâ€‘elemento para que quede encima del patrأ³n */
